            display: flex;
            flex-direction: column;
            justify-content: center;
            align-items: center;
            margin-bottom: 30px;
            border-left: 4px solid #e94560;
        }

        .joke-setup {
            font-size: 1.1rem;
            font-weight: 600;
            margin-bottom: 12px;
            color: #eaeaea;
        }

        .joke-punchline {
            font-size: 1rem;
            color: #f5a623;
            font-style: italic;
            display: none;
        }

        .placeholder {
            color: #a8a8b3;
            font-size: 1rem;
        }

        .btn {
            background-color: #e94560;
            color: #fff;
            border: none;
            padding: 14px 32px;
            font-size: 1rem;
            font-weight: 600;
            border-radius: 50px;
            cursor: pointer;
            transition: background-color 0.3s ease, transform 0.1s ease;
            margin: 8px;
        }

        .btn:hover {
            background-color: #c73652;
        }

        .btn:active {
            transform: scale(0.97);
        }

        .btn-secondary {
            background-color: transparent;
            border: 2px solid #e94560;
            color: #e94560;
        }

        .btn-secondary:hover {
            background-color: #e94560;
            color: #fff;
        }

        .emoji {
            font-size: 2.5rem;
            margin-bottom: 16px;
        }
    </style>
</head>
<body>

    <div class="container">
        <div class="emoji">😄</div>
        <h1>Joke Generator</h1>
        <p class="subtitle">Click the button to hear a joke!</p>

        <div class="joke-box" id="jokeBox">
            <p class="placeholder" id="placeholder">Your joke will appear here...</p>
            <p class="joke-setup" id="jokeSetup"></p>
            <p class="joke-punchline" id="jokePunchline"></p>
        </div>

        <button class="btn" onclick="getJoke()">Tell Me a Joke! 🎲</button>
        <button class="btn btn-secondary" onclick="showPunchline()">Reveal Punchline 👀</button>
    </div>

    <script>
        const jokes = [
            {
                setup: "Why don't scientists trust atoms?",
                punchline: "Because they make up everything! 😄"
            },
            {
                setup: "Why did the scarecrow win an award?",
                punchline: "Because he was outstanding in his field! 🌾"
            },
            {
                setup: "Why don't eggs tell jokes?",
                punchline: "Because they'd crack each other up! 🥚"
            },
            {
                setup: "What do you call a fake noodle?",
                punchline: "An impasta! 🍝"
            }
        ];

        let punchlineVisible = false;

        function getJoke() {
            const randomIndex = Math.floor(Math.random() * jokes.length);
            const joke = jokes[randomIndex];

            document.getElementById('placeholder').style.display = 'none';
            document.getElementById('jokeSetup').textContent = joke.setup;
            document.getElementById('jokePunchline').textContent = joke.punchline;
            document.getElementById('jokePunchline').style.display = 'none';

            punchlineVisible = false;
        }

        function showPunchline() {
            const punchline = document.getElementById('jokePunchline');
            const setup = document.getElementById('jokeSetup').textContent;

            if (!setup) {
                alert("Get a joke first!");
                return;
            }

            if (!punchlineVisible) {
                punchline.style.display = 'block';
                punchlineVisible = true;
            }
        }
    </script>

</body>
</html>
```

## Features

- 🎲 **Random joke selection** from a set of four jokes
- 👀 **Two-step reveal** — the setup shows first, then you click to reveal the punchline
- 🎨 **Styled UI** with a dark theme, smooth hover effects, and clear typography
- 📱 **Responsive design** that works on mobile and desktop

## How It Works

1. Click **"Tell Me a Joke!"** to display a random joke setup
2. Click **"Reveal Punchline"** to see the punchline
3. Click **"Tell Me a Joke!"** again to get a new joke

You can easily add more jokes by adding objects to the `jokes` array in the `<script>` section, following the `{ setup, punchline }` format.
